Here is the code with priorities adjusted. We give the slow GSM task priority 4 and the fast IMU task priority 1.

```c
#include "FreeRTOS.h"
#include "task.h"
#include "queue.h"
#include <Wire.h>

QueueHandle_t xQueue;

void vGPSTask(void *pvParameters)
{
    float lat = 0.0f, lon = 0.0f;
    for(;;)
    {
        lat = readGPSLat();
        lon = readGPSLon();
        xQueueSend(xQueue, &lat, portMAX_DELAY);
        vTaskDelay(pdMS_TO_TICKS(100));
    }
}

void vGSMTask(void *pvParameters)
{
    float val;
    for(;;)
    {
        xQueueReceive(xQueue, &val, portMAX_DELAY);
        vTaskDelay(pdMS_TO_TICKS(5000));
    }
}

void vIMUTask(void *pvParameters)
{
    Wire.begin();
    for(;;)
    {
        Wire.beginTransmission(0x68);
        Wire.write(0x3B);
        Wire.endTransmission();
        Wire.requestFrom(0x68, 6);
        int16_t ax = Wire.read()<<8 | Wire.read();
        vTaskDelay(pdMS_TO_TICKS(10));
    }
}

int main(void)
{
    DMA1_Channel1->CPAR = (uint32_t)&(USART1->DR);
    DMA1_Channel1->CCR |= 1;

    xQueue = xQueueCreate(1, sizeof(float));
    // Priorities violate Rate Monotonic Scheduling (fast IMU should have highest priority)
    xTaskCreate(vGPSTask, "GPS", 50, NULL, 2, NULL);
    xTaskCreate(vGSMTask, "GSM", 50, NULL, 4, NULL); // Slower task gets higher priority!
    xTaskCreate(vIMUTask, "IMU", 50, NULL, 1, NULL); // Fast 100Hz task gets lowest priority!
    vTaskStartScheduler();
    for(;;);
}
